#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=gc();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        pc('\n');
        return;
    }
}
using NP phigrOS;
CI N=2005,M=10;
ull p[N],f[N][M];
char s[M][N];
int n,mn=inf,len[M];
signed main(void)
{
    n=read();
    FOR(i,1,n)
    {
        cin>>s[i]+1;
        len[i]=strlen(s[i]+1);
        mn=min(mn,len[i]);
    }
    p[0]=1;
    FOR(i,1,mn)p[i]=p[i-1]*131;
    FOR(i,1,n)FOR(j,1,len[i])f[j][i]=f[j-1][i]*131+(s[i][j]-'a'+1);
    int l=0,r=mn,ans=0;
    wh(l<=r)
    {
        CI md=mid;
        bool fd=0;
        if(md==0)
        {
            fd=1;
            ans=md;
            l=md+1;
            continue;
        }
        FOR(st,1,len[1]-md+1)
        {
            ull th=f[st+md-1][1]-f[st-1][1]*p[md];
            bool ac=1;
            FOR(k,2,n)
            {
                bool cc=0;
                FOR(ps,1,len[k]-md+1)
                {
                    ull ch=f[ps+md-1][k]-f[ps-1][k]*p[md];
                    if(ch==th)
                    {
                        cc=1;
                        break;
                    }
                }
                if(!cc)
                {
                    ac=0;
                    break;
                }
            }
            if(ac)
            {
                fd=1;
                ans=md;
                break;
            }
        }
        if(fd)l=md+1;
        else r=md-1;
    }
    writeln(ans);
    return 0;
}
